diff --git a/assertj-core/src/main/java/org/assertj/core/api/RecursiveComparisonAssert.java b/assertj-core/src/main/java/org/assertj/core/api/RecursiveComparisonAssert.java
index bf12f3c..5369f32 100644
--- a/assertj-core/src/main/java/org/assertj/core/api/RecursiveComparisonAssert.java
+++ b/assertj-core/src/main/java/org/assertj/core/api/RecursiveComparisonAssert.java
@@ -158,11 +158,11 @@ public class RecursiveComparisonAssert<SELF extends RecursiveComparisonAssert<SE
     objects.assertNotNull(info, actual);
     // at this point, both actual and expected are not null, we can compare them recursively!
     List<ComparisonDifference> differences = determineDifferencesWith(expected);
-    if (!differences.isEmpty()) throw objects.getFailures().failure(info, shouldBeEqualByComparingFieldByFieldRecursively(actual,
-                                                                                                                           expected,
-                                                                                                                           differences,
-                                                                                                                           recursiveComparisonConfiguration,
-                                                                                                                           info.representation()));
+    if (!differences.isEmpty()) throwAssertionError(shouldBeEqualByComparingFieldByFieldRecursively(actual,
+                                                                                                    expected,
+                                                                                                    differences,
+                                                                                                    recursiveComparisonConfiguration,
+                                                                                                    info.representation()));
     return myself;
   }

@@ -205,15 +205,15 @@ public class RecursiveComparisonAssert<SELF extends RecursiveComparisonAssert<SE
    */
   @Override
   public SELF isNotEqualTo(Object other) {
-    if (actual == other) throw objects.getFailures().failure(info, shouldNotBeEqualComparingFieldByFieldRecursively(actual, other,
-                                                                                                                    recursiveComparisonConfiguration,
-                                                                                                                    info.representation()));
+    if (actual == other) throwAssertionError(shouldNotBeEqualComparingFieldByFieldRecursively(actual, other,
+                                                  recursiveComparisonConfiguration,
+                                                  info.representation()));
     if (other != null && actual != null) {
       List<ComparisonDifference> differences = determineDifferencesWith(other);
       if (differences.isEmpty())
-        throw objects.getFailures().failure(info, shouldNotBeEqualComparingFieldByFieldRecursively(actual, other,
-                                                                                                   recursiveComparisonConfiguration,
-                                                                                                   info.representation()));
+        throwAssertionError(shouldNotBeEqualComparingFieldByFieldRecursively(actual, other,
+                                               recursiveComparisonConfiguration,
+                                               info.representation()));
     }
     // either actual or other was null (but not both) or there were no differences
     return myself;
   }
